#!/usr/bin/env python3
"""Compute the ethos keep-closure for vox and list files to remove (dry-run)."""
from __future__ import annotations
import re
from pathlib import Path

ETHOS = Path(".punt-labs/ethos")
KEEP_IDENTITIES = {
    "claude", "jfreeman", "rmh", "gvr", "bwk", "kpz", "mdm", "rop",
    "adb", "djb", "edt", "dna", "mcg", "rej", "jms",
}


def field_scalar(text: str, key: str) -> str | None:
    m = re.search(rf"^{key}:\s*(\S+)\s*$", text, re.M)
    return m.group(1) if m else None


def field_list(text: str, key: str) -> list[str]:
    # crude YAML list: "key:\n  - a\n  - b"
    out: list[str] = []
    m = re.search(rf"^{key}:\s*$", text, re.M)
    if not m:
        return out
    for line in text[m.end():].splitlines():
        s = line.strip()
        if s.startswith("- "):
            out.append(s[2:].strip())
        elif s and not s.startswith("#"):
            break
    return out


keep_pers, keep_ws, keep_tal = set(), set(), set()
missing = []
for h in sorted(KEEP_IDENTITIES):
    f = ETHOS / "identities" / f"{h}.yaml"
    if not f.exists():
        missing.append(h)
        continue
    t = f.read_text()
    if (p := field_scalar(t, "personality")):
        keep_pers.add(p)
    if (w := field_scalar(t, "writing_style")):
        keep_ws.add(w)
    keep_tal.update(field_list(t, "talents"))

# roles from engineering team members that are kept
team = (ETHOS / "teams" / "engineering.yaml").read_text()
keep_roles = set()
for block in re.split(r"\n\s*-\s+identity:", team):
    id_m = re.match(r"\s*(\S+)", block)
    role_m = re.search(r"role:\s*(\S+)", block)
    if id_m and role_m and id_m.group(1) in KEEP_IDENTITIES:
        keep_roles.add(role_m.group(1))

keepmap = {
    "identities": {f"{h}.yaml" for h in KEEP_IDENTITIES},
    "personalities": {f"{p}.md" for p in keep_pers},
    "writing-styles": {f"{w}.md" for w in keep_ws},
    "talents": {f"{x}.md" for x in keep_tal},
    "roles": {f"{r}.md" for r in keep_roles},
    "agents": {f"{h}.md" for h in KEEP_IDENTITIES},
}
LEDGER_KEEP = {"missions.jsonl", "missions", "sessions", ".create.lock"}

print("== KEEP closure ==")
for cat, keep in keepmap.items():
    print(f"{cat}: keep {sorted(keep)}")
print(f"roles derived: {sorted(keep_roles)}")
print(f"missing identity files: {missing}")

print("\n== REMOVE list ==")
removed = 0
for cat in ("identities", "personalities", "writing-styles", "talents", "roles", "agents"):
    d = ETHOS / cat
    if not d.exists():
        continue
    for f in sorted(d.iterdir()):
        if f.name not in keepmap[cat]:
            print(f"rm {cat}/{f.name}")
            removed += 1
# teams: keep only engineering (trim members separately)
for f in sorted((ETHOS / "teams").iterdir()):
    if f.stem != "engineering":
        print(f"rm teams/{f.name}")
        removed += 1
print(f"\nTotal files to remove: {removed}")

